var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"정말 감사해요. 아무런 관계도 없으신데 저희 마을을 위해 나서 주시다니…….","JPN":"本当にありがとうございます。無関係な方なのにうちの村のために……","ENG":"Thank you very much. You stood up for us even when you didn’t have to...","TWN":"真的很謝謝你，明明不干你的事，竟然願意爲我們的村子挺身而出………"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런 말씀 마십시오, 모네 어머님. 모네 양에게는 일전에 크게 도움 받았으니까요.","JPN":"そんなに感謝されるようなことではありません。モネには以前かなり助けてもらいましてね。","ENG":"Don’t say that. Mone has helped us a great deal in the past.","TWN":"伯母，別那麼說。不久前我受到莫妮很大的幫助呢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"서로 도우며 사는 거 아니겠습니까. 하. 하. 하.","JPN":"お互い助け合わねば。ア・ハ・ハ・ハ。","ENG":"We have to help each other, right? Ha, ha, ha.","TWN":"最美的風景不就是人嗎，哈，哈，哈。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"어쩜, 믿음직스러우셔라.","JPN":"あらあ、なんて頼もしい方かしら。","ENG":"Oh my, you really are a man of virtue.","TWN":"真是個值得信賴的人。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"저희 애가 사고는 안 치고 다닐까 걱정이 많았는데, 도시에서 참 좋은 분들을 만났네요.","JPN":"うちの子が都会で迷惑かけたらどうしようと心配していましたが、とてもいい方々に出会えたんですね。","ENG":"I was always worried about my girl, but I see she met very good people in the city.","TWN":"我本來很擔心我們家孩子會不會闖禍，沒想到在城市裡遇到好人呢！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그런데 모네 넌 애가 겁도 없이 총 든 사람한테 달려들기나 하고…….","JPN":"でもモネ、銃を持っている人に立ち向かうなんて……","ENG":"And Mone, what were you thinking, running to fight armed men?","TWN":"不過莫妮，你這孩子竟然衝到那群手裡拿著槍的人面前………"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"자, 잘못했슴다…….","JPN":"ご、ごめんなさい……","ENG":"I-I’m sorry...","TWN":"對不起…"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"어머나, 내 정신 좀 봐. 수다 떨다 식사도 못 드시게 했네요.","JPN":"あらら、私としたことが。おしゃべりに夢中になってお食事のことをうっかりしていましたわ。","ENG":"Oh, where are my manners. You must be hungry.","TWN":"哎呀，你看看我，只顧著聊天，害你們都沒辦法好好吃飯。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"남편이 먼 바다로 나가서 차릴 건 부족하지만 정성껏 챙겨 봤어요. 많이 드세요.","JPN":"主人が沖まで出て釣ってきたものです。お粗末様ですが、ぜひ召し上がってください。","ENG":"My husband is out at sea and we don’t have much right now, but I did my best with what I have. Please help yourselves.","TWN":"因為莫妮的爸爸出海去了，家裡沒什麼東西，一點家常菜，你們不要客氣。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"우와, 엄청 맛있다! 이거 생선회 맞아요?","JPN":"うわぁー美味しい！　これ本当に刺身ですか？","ENG":"Wow, this is great! Are you sure this is raw fish?","TWN":"哇，真的很好吃！這是生魚片吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"후훗. 네. 오래 재워 둘 겨를이 없었는데 입맛에 맞으시다니 다행이네요.","JPN":"フフッ。下処理する時間がなくて心配したのですが、お口に合ってよかったですわ。","ENG":"*Smile* Yes. I didn’t have the time to marinate it fully, but I’m glad you like it.","TWN":"呵呵，對啊。沒什麼時間準備，幸好合你的胃口。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이 바닷가재도 살이 무척 부드럽군요. 사진 한 번 찍은 대가치고는 호사스럽네요.","JPN":"このエビも身がぷりぷりでとても柔らかいです。たった一枚の写真のお礼と言うには、贅沢すぎますね。","ENG":"This lobster is so creamy. What a treat we get, just for taking a simple selfie.","TWN":"這龍蝦肉也好Q彈。作爲拍一張照的代價，未免太奢侈。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"혹시 이 신선한 해산물들이…… 저 윤기가 흐르는 피부의 비결인가?","JPN":"もしかしてこの新鮮な海産物に……あの艶やかな肌の秘訣が？","ENG":"All this fresh seafood... Perhaps this is the key to her silky soft skin?","TWN":"難道這些新鮮的海鮮……就皮膚Q彈的秘訣嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠흠! 크흠!","JPN":"コホンコホン！　コホン！","ENG":"Ahem! Ahem!","TWN":"咳嗯嗯！咳嗯！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어머님, 방금 전에 마을로 들이닥쳤던 자들은 어떻게 된 겁니까?","JPN":"お母さん、さっき村を襲ってきた連中は何者ですか？","ENG":"Ma’am, who were those people who attacked your village?","TWN":"伯母，剛闖進村子的那些人到底是怎麼回事？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"아, 실은…….","JPN":"あ、実は……","ENG":"Oh, them...","TWN":"是這樣的…"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};